async function checkAccess(){const e=document.getElementById("admin-pass").value,t=document.getElementById("login-error");try{if(await hashString(e)==="4de9a48824f9ca72125798e7eca051baf13c3e3a403d7fdcf0662f4844fd28ea"){document.getElementById("login-section").style.display="none",document.getElementById("stats-content").style.display="block",loadStats()}else t.style.display="block",t.innerText="Incorrect Password"}catch(n){console.error("Auth error:",n),t.style.display="block",t.innerText="Security error occurred."}}async function hashString(e){const t=(new TextEncoder).encode(e),n=await crypto.subtle.digest("SHA-256",t);return Array.from(new Uint8Array(n)).map(e=>e.toString(16).padStart(2,"0")).join("")}async function loadStats(){const e=document.getElementById("visit-count");try{const t=await fetch("https://api.counterapi.dev/v1/josemanuel31675-cv/visits");if(t.status===404||t.status===400){e.innerText="0";return}const n=await t.json();e.innerText=n.count!==undefined?n.count:"0"}catch(t){console.error("Stats fetch error:",t),e.innerText="0"}}
